import random

def shuffle_deck(deck):
    random.shuffle(deck)
    return deck

def deal_cards(deck, num):
    return [deck.pop() for _ in range(min(num, len(deck)))]

def has_basic_pokemon(cards):
    return any(card.get("supertype") == "たね" for card in cards)

def get_card_back_view(cards):
    card_back_url = "https://images-wixmp-ed30a86b8c4ca887773594c2.wixmp.com/f/4f7705ec-8c49-4eed-a56e-c21f3985254c/dah43cy-a8e121cb-934a-40f6-97c7-fa2d77130dd5.png/v1/fit/w_828,h_1148/pokemon_card_backside_in_high_resolution_by_atomicmonkeytcg_dah43cy-414w-2x.png?token=eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..9GzaYS7sd8RPY5FlHca09J9ZQZ9D9zI69Ru-BsbkLDA"
    return [{**card, "image_url": card_back_url} for card in cards]
